class Solution:
    def findEvenNumbers(self, digits: List[int]) -> List[int]:
        cnt = [0] * 10
        for d in digits:
            cnt[d] += 1

        ans = []
        for num in range(100, 1000, 2):  # even 3-digit numbers only
            a = num // 100
            b = (num // 10) % 10
            c = num % 10

            if cnt[a] == 0 or cnt[c] == 0 or cnt[b] == 0:
                continue

            if a == b == c:
                if cnt[a] >= 3:
                    ans.append(num)
            elif a == b:
                if cnt[a] >= 2:
                    ans.append(num)
            elif a == c:
                if cnt[a] >= 2:
                    ans.append(num)
            elif b == c:
                if cnt[b] >= 2:
                    ans.append(num)
            else:
                ans.append(num)

        return ans
```

